+private:
+  ACTION_DEFINITION(Action);
+
+  typedef actionlib::ServerGoalHandle<Action> GoalHandle;
+  typedef boost::shared_ptr<Result> ResultPtr;
+
+  uint8_t state_;
+
+  bool req_abort_;
+  bool req_succeed_;
+  ResultConstPtr req_result_;
